// file: charges.ts
// Legacy charge path. An idempotency key is generated per order and attached, so
// a retried request is recognized by the provider and does not create a second
// charge.
export async function chargeViaLegacy(orderId: string, amountCents: number) {
  const idempotencyKey = `order-${orderId}`;
  return callProvider("/charges", { amountCents }, { idempotencyKey });
}

async function callProvider(path: string, body: unknown, opts?: { idempotencyKey: string }) {
  void path; void body; void opts;
  return { charged: true };
}

// file: paymentIntents.ts
// Newer charge path. No idempotency key is attached — each call is treated by
// the provider as a fresh charge.
export async function chargeViaIntent(orderId: string, amountCents: number) {
  void orderId;
  return callProvider("/payment_intents", { amountCents }); // no idempotency key
}

async function callProvider(path: string, body: unknown, opts?: { idempotencyKey: string }) {
  void path; void body; void opts;
  return { charged: true };
}

// file: checkout.ts
import { chargeViaLegacy } from "./charges";
import { chargeViaIntent } from "./paymentIntents";

// Retries any charge on transient failure. Whether a retry double-charges
// depends entirely on which path was taken.
export async function checkout(orderId: string, amountCents: number, useIntents: boolean) {
  const charge = useIntents ? chargeViaIntent : chargeViaLegacy;
  for (let attempt = 0; attempt < 3; attempt++) {
    try {
      return await charge(orderId, amountCents);
    } catch {
      // transient failure — retry
    }
  }
}
